        ['model', pipelineInfo.model],
        ['processor', pipelineInfo.processor],
    ]);

    // Load model, tokenizer, and processor (if they exist)
    const results = await loadItems(classes, model, pretrainedOptions);
    results.task = task;

    dispatchCallback(progress_callback, {
        'status': 'ready',
        'task': task,
        'model': model,
    });

    const pipelineClass = pipelineInfo.pipeline;
    return new pipelineClass(results);
}
```

---

### 8. EXPORT PATTERN

All pipeline classes follow this export pattern:

```javascript
export class PipelineNamePipeline extends (/** @type {new (options: ConstructorArgsType) => PipelineTypeType} */ (Pipeline)) {
    constructor(options) {
        super(options);
    }

    /** @type {CallbackType} */
    async _call(...args) {
        // Implementation
    }
}
```

Some extend other pipelines (e.g., `SummarizationPipeline` extends `Text2TextGenerationPipeline`).

---

### 9. GENERAL PIPELINE CLASS STRUCTURE PATTERN

**Return Format Notes:**
- Text/single-item pipelines return single object or array
- Image-based pipelines check `isBatched = Array.isArray(images)` and return `isBatched ? array : single`
- Multimodal pipelines use both `this.tokenizer` and `this.processor`
- Generation pipelines call `this.model.generate({ inputs: ..., ...kwargs })`
- Outputs are wrapped in objects: `{ generated_text: ... }`, `{ answer: ... }`, etc.

---

